def factorial(n):
    if n <= 1: return 1
    return n * factorial(n-1)

def dynamic_logger(level, *msgs, **metadata):
    print(f'[{level.upper()}] {' '.join(msgs)}')
    for k, v in metadata.items():
        print(f'{k}: {v}')
